func (v *Validation) AddError(key, message string) {
	Name := key
	Field := ""

	Label := ""
	parts := strings.Split(key, ".")
	if len(parts) == 3 {
		Field = parts[0]
		Name = parts[1]
		Label = parts[2]
		if len(Label) == 0 {
			Label = Field
		}
	}

	err := &Error{
		Message:	Label + " " + message,
		Key:		key,
		Name:		Name,
		Field:		Field,
		Label:		Label,
	}
	v.setError(err)
}
